let totalClicks = toscalar(
    customEvents
    | where name == "searchResultClick"
    | where timestamp {TimeRange}
    | count
);
customEvents
| where name == "searchResultClick"
| where timestamp {TimeRange}
| extend d = customDimensions
| extend primaryMatchType = tostring(d.primaryMatchType)
| where isnotempty(primaryMatchType)
| summarize PresenceCount = count() by primaryMatchType
| extend PresencePct = iif(totalClicks > 0, round(toreal(PresenceCount) / totalClicks * 100, 1), 0.0)
| order by PresenceCount desc
| project ['Primary Match Type'] = primaryMatchType, Count = PresenceCount, ['Presence %'] = PresencePct

// 1. Create a master list of your buckets with an explicit order hint
let AllBuckets = datatable(RankBucket:string, OrderHint:int) [
    "Ranks 1 - 5", 1,
    "Ranks 6 - 10", 2,
    "Ranks 11 - 25", 3,
    "Ranks 26+", 4
];
// 2. Get actual click data and map to matching bucket strings
let ClickData = customEvents 
| where name == "searchResultClick" 
| where timestamp {TimeRange} 
| extend rank = toint(customMeasurements.rank)
| extend RankBucket = case(
    rank >= 1 and rank <= 5,   "Ranks 1 - 5",
    rank >= 6 and rank <= 10,  "Ranks 6 - 10",
    rank >= 11 and rank <= 25, "Ranks 11 - 25",
    "Ranks 26+"
)
| summarize ClickCount = count() by RankBucket;
// 3. Join them together, sort by OrderHint, then drop OrderHint right before outputting
AllBuckets
| join kind=leftouter ClickData on RankBucket
| extend ClickCount = iff(isempty(ClickCount), 0, ClickCount)
| order by OrderHint asc
| project RankBucket, ClickCount
